parameters.text:
=# Role
你是一位儿童英语课程体验设计顾问，擅长根据现有课程概览，为用户生成可直接点击使用的“重新生成调整需求参考”。

# Task
基于输入的课程信息，生成 4-6 条中文调整建议。每条建议都应该像用户会输入到重新生成弹窗里的自然语言提示词，具体、可执行、有差异。

# Course Info
- 课程标题：{{ $json.courseTitle }}
- 主题：{{ $json.theme }}
- 年龄：{{ $json.age }}
- 课长：{{ $json.duration }}
- 班级规模：{{ $json.scale }}
- 词汇：{{ $json.vocabulary }}
- 句型/语法：{{ $json.grammar }}
- 能力侧重：{{ $json.skills }}
- 体验路径：{{ $json.paths }}
- 故事情境：{{ $json.storyContext }}
- 终极产出：{{ $json.keyOutcome }}
- SEL目标：{{ $json.selGoals }}
- PERMA目标：{{ $json.permaGoals }}

# Requirements
- 建议要覆盖不同调整方向，例如：故事情境、4E课堂旅程、语言工具箱、最终产出、SEL/PERMA成长体验、课堂互动机制。
- 每条 25-60 个中文字，避免空泛词，如“更有趣”“更丰富”。
- 不要输出 Markdown，不要解释。
- 只输出有效 JSON。

# Output JSON
{
  "tips": [
    "希望...",
    "希望..."
  ]
}

parameters.jsCode:
const raw = $input.item.json;
let tips = [];

if (Array.isArray(raw.tips)) {
  tips = raw.tips;
} else if (raw.text) {
  const text = String(raw.text).trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  try {
    const parsed = JSON.parse(text);
    tips = Array.isArray(parsed.tips) ? parsed.tips : [];
  } catch (error) {
    tips = text.split(/\n+/).map(line => line.replace(/^[-\d.、\s]+/, '').trim());
  }
}

tips = tips
  .map(tip => String(tip || '').trim())
  .filter(Boolean)
  .slice(0, 6);

if (tips.length === 0) {
  tips = [
    '希望故事情境更有悬念，让学生从一封任务信或线索卡进入挑战。',
    '希望Execute阶段加入小组合作竞赛，让最终产出更有挑战性。',
    '希望语言工具箱更聚焦口语输出，增加可反复套用的课堂句型。',
    '希望成长目标更突出团队协作、情绪表达和解决问题后的成就感。'
  ];
}

return { tips };
